f := Module[{
    A = {0, 0, 0};
    B = {2, 0, 0};
    D = {0, 1, 0};
    D1 = {0, 1, 2};
    A1 = {0, 0, 2};
    E = Midpoint[{D, D1}];
    F = Midpoint[{A, B}];
    G = Midpoint[{C, C1}];
    C = {2, 1, 0};
    C1 = {2, 1, 2};
    A1E = E - A1;
    GF = F - G;
    dot = A1E • GF;
    magnitudes = Abs[A1E] * Abs[GF];
    cosine = dot / magnitudes;
    cosine
}];

